    gmt_modified = CURRENT_TIMESTAMP
    ,title = #{notificationInstanceEntity.title}
    ,content = #{notificationInstanceEntity.content}
    ,read_status = #{notificationInstanceEntity.readStatus}
    ,read_time = #{notificationInstanceEntity.readTime}

where id = #{notificationInstanceEntity.id}
 and tenant_id = #{notificationInstanceEntity.tenantId}

